class PaymentProcessor {
  final InAppPurchase _inAppPurchase = InAppPurchase.instance;

  Future<void> init() async {
    await _inAppPurchase.initialize();
  }

  Future<void> makePayment(String productId) async {
    if (!_inAppPurchase.isAvailable()) {
      throw Exception('In-app purchases are not available.');
    }

    final ProductDetailsResponse productDetailResponse =
        await _inAppPurchase.queryProductDetails({productId});

    if (productDetailResponse.productDetails.isEmpty) {
      throw Exception('No products found for purchase.');
    }

    final ProductDetails product = productDetailResponse.productDetails.first;

    final PurchaseParam purchaseParam = PurchaseParam(
      productDetails: product,
    );

    await _inAppPurchase.buyNonConsumable(purchaseParam: purchaseParam);
  }
}